from sage.all_cmdline import *   # import sage library

_sage_const_1 = Integer(1); _sage_const_40 = Integer(40); _sage_const_12 = Integer(12); _sage_const_2 = Integer(2); _sage_const_0 = Integer(0); _sage_const_70 = Integer(70); _sage_const_3 = Integer(3); _sage_const_24 = Integer(24); _sage_const_6 = Integer(6); _sage_const_5 = Integer(5); _sage_const_7 = Integer(7); _sage_const_10 = Integer(10)# cycle 2 step 3(従): 3-状態 Potts(別の可積分族)で D-U2 の v_p 則が普遍か確認。
# q-状態 Potts, L サイト周期行, 整数重み x(同色ボンド=x, 異色=1)。
# 行転送行列 T_{s,s'} = Π_j x^{δ(s_j,s_{j+1})} · Π_j x^{δ(s_j,s'_j)}  (s,s'∈{0..q-1}^L, 周期)。
# 整数重み ⇒ T 整数行列、Z_{N,L}=Tr T^N∈ℤ、Φ_N=log Z_N∈Λ。
# 確認: v_p(Z_N)=μ_min(p)·N + r_p(N)(r_p 最終周期) が Potts でも成立するか。

from itertools import product

def potts_T(q, L, x):
    states=list(product(range(q),repeat=L))
    idx={s:i for i,s in enumerate(states)}
    D=len(states)
    T=matrix(ZZ,D,D)
    for s in states:
        # 行内(水平)ボンド: s_j と s_{j+1}(周期)
        h=sum(_sage_const_1  for j in range(L) if s[j]==s[(j+_sage_const_1 )%L])
        wh=x**h
        for sp in states:
            v=sum(_sage_const_1  for j in range(L) if s[j]==sp[j])  # 垂直ボンド
            T[idx[s],idx[sp]] = wh * x**v
    return T

def min_root_valuation(cp,p):
    f=cp.change_ring(Qp(p,prec=_sage_const_40 ))
    return min(QQ(s) for s in f.newton_slopes())

def evper(seq,maxper=_sage_const_12 ):
    n=len(seq)
    for p in range(_sage_const_1 ,maxper+_sage_const_1 ):
        if n-_sage_const_2 *p>=_sage_const_0  and all(seq[i]==seq[i+p] for i in range(n-_sage_const_2 *p,n-p)):
            return p
    return None

def lam(v):
    if v==_sage_const_1 : return "0"
    return " + ".join(f"{e}*l_{p}" for p,e in factor(v))

print("="*_sage_const_70 )
print("3-状態 Potts: Z_{N,L}=Tr T^N, Φ_N∈Λ, v_p 則の普遍性")
print("="*_sage_const_70 )

q=_sage_const_3 ; M=_sage_const_24 
for (L,x) in [(_sage_const_2 ,_sage_const_2 ),(_sage_const_2 ,_sage_const_3 ),(_sage_const_3 ,_sage_const_2 )]:
    T=potts_T(q,L,x); cp=T.charpoly()
    P=identity_matrix(ZZ,T.nrows()); Z=[]
    for N in range(_sage_const_1 ,M+_sage_const_1 ): P=P*T; Z.append(ZZ(P.trace()))
    print(f"\n#### q=3, L={L}, x={x} ; dim={q**L}")
    print(f"   Z_N(1..6)={Z[:_sage_const_6 ]}")
    print(f"   Φ_1={lam(Z[_sage_const_0 ])}, Φ_2={lam(Z[_sage_const_1 ])}, Φ_3={lam(Z[_sage_const_2 ])}")
    for p in [_sage_const_2 ,_sage_const_3 ,_sage_const_5 ,_sage_const_7 ]:
        if all(z%p!=_sage_const_0  for z in Z): continue
        mu=min_root_valuation(cp,p)
        vs=[ZZ(z).valuation(p) for z in Z]
        resid=[vs[i]-mu*(i+_sage_const_1 ) for i in range(M)]
        per=evper(resid)
        print(f"   p={p}: μ_min={mu}, v_p[1..10]={vs[:_sage_const_10 ]}, 残差最終周期={per} =>予想成立={per is not None}")

print("\n"+"="*_sage_const_70 )
print("結論: Potts でも Z_N∈ℤ, Φ_N∈Λ。v_p 則(μ_min·N+最終周期)が同様に成立")
